import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import API from "../services/api";
import "../styles/AddMatch.css";

function AddMatch() {
  const [formData, setFormData] = useState({
    teamA: "",
    teamB: "",
    scoreA: "0/0",
    scoreB: "0/0",
    overs: "0.0",
    status: "Upcoming",
    players: []
  });

  const [availablePlayers, setAvailablePlayers] = useState([]);
  const [selectedPlayer, setSelectedPlayer] = useState(null);
  const [playerStats, setPlayerStats] = useState({
    runs: 0,
    wickets: 0,
    ballsFaced: 0,
    strikeRate: 0,
    battingAvg: 0
  });
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handlePlayerStatsChange = (e) => {
    const { name, value } = e.target;
    setPlayerStats({ ...playerStats, [name]: name === 'strikeRate' || name === 'battingAvg' ? parseFloat(value) || 0 : parseInt(value) || 0 });
  };

  const fetchPlayersByTeam = async (team) => {
    if (!team) return;
    try {
      const res = await API.get(`/players/team/${team}`);
      setAvailablePlayers(res.data);
    } catch (err) {
      console.error("Error fetching players:", err);
    }
  };

  const handleAddPlayer = () => {
    if (!selectedPlayer) {
      setError("Please select a player");
      return;
    }

    const playerData = {
      playerId: selectedPlayer._id,
      name: selectedPlayer.name,
      team: selectedPlayer.team,
      role: selectedPlayer.role,
      runs: playerStats.runs,
      wickets: playerStats.wickets,
      ballsFaced: playerStats.ballsFaced,
      strikeRate: playerStats.strikeRate,
      battingAvg: playerStats.battingAvg
    };

    setFormData({
      ...formData,
      players: [...formData.players, playerData]
    });

    setSelectedPlayer(null);
    setPlayerStats({
      runs: 0,
      wickets: 0,
      ballsFaced: 0,
      strikeRate: 0,
      battingAvg: 0
    });
    setError("");
  };

  const handleRemovePlayer = (index) => {
    setFormData({
      ...formData,
      players: formData.players.filter((_, i) => i !== index)
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await API.post("/matches", formData);
      alert("Match added successfully!");
      navigate("/matches");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to add match");
    }
  };

  return (
    <div className="add-match-container">
      <div className="auth-card">
        <h2>Add New Match</h2>
        {error && <p className="error-msg">{error}</p>}

        <form onSubmit={handleSubmit}>
          <h3>Match Details</h3>

          <div className="input-group">
            <label>Team A</label>
            <input 
              type="text" 
              name="teamA" 
              value={formData.teamA} 
              onChange={(e) => {
                handleChange(e);
                fetchPlayersByTeam(e.target.value);
              }}
              required 
            />
          </div>

          <div className="input-group">
            <label>Team B</label>
            <input type="text" name="teamB" value={formData.teamB} onChange={handleChange} required />
          </div>

          <div className="input-group">
            <label>Score A (e.g., 150/3)</label>
            <input type="text" name="scoreA" value={formData.scoreA} onChange={handleChange} />
          </div>

          <div className="input-group">
            <label>Score B (e.g., 140/5)</label>
            <input type="text" name="scoreB" value={formData.scoreB} onChange={handleChange} />
          </div>

          <div className="input-group">
            <label>Overs (e.g., 18.2)</label>
            <input type="text" name="overs" value={formData.overs} onChange={handleChange} />
          </div>

          <div className="input-group">
            <label>Status</label>
            <select name="status" value={formData.status} onChange={handleChange} style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #ddd' }}>
              <option value="Upcoming">Upcoming</option>
              <option value="Live">Live</option>
              <option value="Completed">Completed</option>
            </select>
          </div>

          <hr style={{ margin: '20px 0' }} />

          <h3>Add Players to Match</h3>

          {formData.teamA && (
            <div className="player-input-section">
              <div className="input-group">
                <label>Select Player</label>
                <select 
                  value={selectedPlayer?._id || ""} 
                  onChange={(e) => {
                    const player = availablePlayers.find(p => p._id === e.target.value);
                    setSelectedPlayer(player || null);
                  }}
                >
                  <option value="">Choose a player from {formData.teamA}</option>
                  {availablePlayers.map(player => (
                    <option key={player._id} value={player._id}>
                      {player.name} ({player.role})
                    </option>
                  ))}
                </select>
              </div>

              {selectedPlayer && (
                <div className="player-stats-grid">
                  <div className="input-group">
                    <label>Runs</label>
                    <input type="number" name="runs" value={playerStats.runs} onChange={handlePlayerStatsChange} min="0" />
                  </div>
                  <div className="input-group">
                    <label>Wickets</label>
                    <input type="number" name="wickets" value={playerStats.wickets} onChange={handlePlayerStatsChange} min="0" />
                  </div>
                  <div className="input-group">
                    <label>Balls Faced</label>
                    <input type="number" name="ballsFaced" value={playerStats.ballsFaced} onChange={handlePlayerStatsChange} min="0" />
                  </div>
                  <div className="input-group">
                    <label>Strike Rate</label>
                    <input type="number" name="strikeRate" value={playerStats.strikeRate} onChange={handlePlayerStatsChange} step="0.01" min="0" />
                  </div>
                  <div className="input-group">
                    <label>Batting Avg</label>
                    <input type="number" name="battingAvg" value={playerStats.battingAvg} onChange={handlePlayerStatsChange} step="0.01" min="0" />
                  </div>
                </div>
              )}

              <button type="button" onClick={handleAddPlayer} className="auth-btn" style={{ marginTop: '10px' }}>
                Add Player
              </button>
            </div>
          )}

          {formData.players.length > 0 && (
            <div className="added-players">
              <h4>Players Added ({formData.players.length})</h4>
              <ul>
                {formData.players.map((player, index) => (
                  <li key={index} className="player-item">
                    <div className="player-info">
                      <strong>{player.name}</strong> ({player.role})
                      <br />
                      <small>{player.runs} runs | {player.wickets}W | SR: {player.strikeRate}</small>
                    </div>
                    <button 
                      type="button" 
                      onClick={() => handleRemovePlayer(index)}
                      className="remove-btn"
                    >
                      Remove
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          )}

          <button type="submit" className="auth-btn" style={{ marginTop: '20px' }}>Save Match</button>
        </form>
      </div>
    </div>
  );
}

export default AddMatch;
